export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    // CORS headers for browser requests
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      // Request context passed to internal services
      const requestContext = {
        requestId: crypto.randomUUID(),
        timestamp: Date.now(),
        clientIP: request.headers.get('CF-Connecting-IP'),
        userAgent: request.headers.get('User-Agent'),
        country: request.cf?.country || 'unknown',
      };

      // Route requests to appropriate internal workers
      let response;

      if (path.startsWith('/api/auth')) {
        response = await routeToService(env.AUTH_SERVICE, request, requestContext, '/api/auth');
      } else if (path.startsWith('/api/users')) {
        // Authenticate first, then route to user service
        const authResult = await authenticateRequest(env.AUTH_SERVICE, request, requestContext);
        if (!authResult.authenticated) {
          return new Response(JSON.stringify({ error: 'Unauthorized', message: authResult.message }), {
            status: 401,
            headers: { 'Content-Type': 'application/json', ...corsHeaders },
          });
        }
        requestContext.userId = authResult.userId;
        requestContext.roles = authResult.roles;
        response = await routeToService(env.USER_SERVICE, request, requestContext, '/api/users');
      } else if (path.startsWith('/api/data')) {
        const authResult = await authenticateRequest(env.AUTH_SERVICE, request, requestContext);
        if (!authResult.authenticated) {
          return new Response(JSON.stringify({ error: 'Unauthorized', message: authResult.message }), {
            status: 401,
            headers: { 'Content-Type': 'application/json', ...corsHeaders },
          });
        }
        requestContext.userId = authResult.userId;
        requestContext.roles = authResult.roles;
        response = await routeToService(env.DATA_SERVICE, request, requestContext, '/api/data');
      } else if (path.startsWith('/api/notifications')) {
        const authResult = await authenticateRequest(env.AUTH_SERVICE, request, requestContext);
        if (!authResult.authenticated) {
          return new Response(JSON.stringify({ error: 'Unauthorized', message: authResult.message }), {
            status: 401,
            headers: { 'Content-Type': 'application/json', ...corsHeaders },
          });
        }
        requestContext.userId = authResult.userId;
        response = await routeToService(env.NOTIFICATION_SERVICE, request, requestContext, '/api/notifications');
      } else if (path === '/health') {
        response = await healthCheck(env);
      } else {
        return new Response(JSON.stringify({
          error: 'Not Found',
          availableRoutes: ['/api/auth/*', '/api/users/*', '/api/data/*', '/api/notifications/*', '/health'],
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json', ...corsHeaders },
        });
      }

      // Add CORS and tracking headers to response
      const newHeaders = new Headers(response.headers);
      Object.entries(corsHeaders).forEach(([key, value]) => newHeaders.set(key, value));
      newHeaders.set('X-Request-ID', requestContext.requestId);
      newHeaders.set('X-Response-Time', `${Date.now() - requestContext.timestamp}ms`);

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: newHeaders,
      });
    } catch (error) {
      console.error('Gateway error:', error);
      return new Response(JSON.stringify({
        error: 'Internal Gateway Error',
        message: error.message,
      }), {
        status: 502,
        headers: { 'Content-Type': 'application/json', ...corsHeaders },
      });
    }
  },
};

async function routeToService(service, originalRequest, context, stripPrefix) {
  const url = new URL(originalRequest.url);
  const internalPath = stripPrefix ? url.pathname.replace(stripPrefix, '') || '/' : url.pathname;
  const internalUrl = new URL(internalPath + url.search, 'http://internal-service');

  const headers = new Headers(originalRequest.headers);
  headers.set('X-Request-Context', JSON.stringify(context));
  headers.set('X-Forwarded-For', context.clientIP || '');
  headers.set('X-Request-ID', context.requestId);

  const init = {
    method: originalRequest.method,
    headers,
  };

  if (!['GET', 'HEAD'].includes(originalRequest.method)) {
    init.body = originalRequest.body;
  }

  return service.fetch(internalUrl.toString(), init);
}

async function authenticateRequest(authService, request, context) {
  try {
    const authHeader = request.headers.get('Authorization');
    if (!authHeader) {
      return { authenticated: false, message: 'No authorization header provided' };
    }

    const verifyRequest = new Request('http://internal-service/verify', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Request-Context': JSON.stringify(context),
      },
      body: JSON.stringify({ token: authHeader.replace('Bearer ', '') }),
    });

    const response = await authService.fetch(verifyRequest);
    const result = await response.json();

    if (response.ok && result.valid) {
      return { authenticated: true, userId: result.userId, roles: result.roles };
    }
    return { authenticated: false, message: result.message || 'Invalid token' };
  } catch (error) {
    console.error('Auth verification error:', error);
    return { authenticated: false, message: 'Authentication service unavailable' };
  }
}

async function healthCheck(env) {
  const services = {
    auth: env.AUTH_SERVICE,
    user: env.USER_SERVICE,
    data: env.DATA_SERVICE,
    notification: env.NOTIFICATION_SERVICE,
  };

  const checks = {};

  for (const [name, service] of Object.entries(services)) {
    try {
      const start = Date.now();
      const resp = await service.fetch('http://internal-service/health');
      const latency = Date.now() - start;
      const body = await resp.json();
      checks[name] = { status: resp.ok ? 'healthy' : 'unhealthy', latency: `${latency}ms`, ...body };
    } catch (error) {
      checks[name] = { status: 'unreachable', error: error.message };
    }
  }

  const allHealthy = Object.values(checks).every((c) => c.status === 'healthy');

  return new Response(JSON.stringify({
    status: allHealthy ? 'healthy' : 'degraded',
    gateway: 'healthy',
    services: checks,
    timestamp: new Date().toISOString(),
  }), {
    status: allHealthy ? 200 : 503,
    headers: { 'Content-Type': 'application/json' },
  });
}

