export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    // Parse request context from gateway
    const context = parseContext(request);

    try {
      // Internal routing
      if (path === '/health') {
        return jsonResponse({ status: 'healthy', service: 'auth', uptime: Date.now() });
      }

      if (path === '/verify' && method === 'POST') {
        return await verifyToken(request, env);
      }

      if (path === '/login' && method === 'POST') {
        return await login(request, env);
      }

      if (path === '/register' && method === 'POST') {
        return await register(request, env);
      }

      if (path === '/refresh' && method === 'POST') {
        return await refreshToken(request, env);
      }

      if (path === '/logout' && method === 'POST') {
        return await logout(request, env, context);
      }

      return jsonResponse({ error: 'Auth route not found' }, 404);
    } catch (error) {
      console.error('Auth service error:', error);
      return jsonResponse({ error: 'Auth service error', message: error.message }, 500);
    }
  },
};

async function login(request, env) {
  const { email, password } = await request.json();

  if (!email || !password) {
    return jsonResponse({ error: 'Email and password are required' }, 400);
  }

  // Look up user in KV store
  const userRecord = await env.AUTH_KV.get(`user:${email}`, 'json');

  if (!userRecord) {
    return jsonResponse({ error: 'Invalid credentials' }, 401);
  }

  // Verify password (using a simple hash comparison - in production use proper bcrypt/argon2)
  const passwordHash = await hashPassword(password, userRecord.salt);
  if (passwordHash !== userRecord.passwordHash) {
    return jsonResponse({ error: 'Invalid credentials' }, 401);
  }

  // Generate JWT-like token
  const token = await generateToken(userRecord.userId, userRecord.roles, env);
  const refreshToken = crypto.randomUUID();

  // Store refresh token
  await env.AUTH_KV.put(`refresh:${refreshToken}`, JSON.stringify({
    userId: userRecord.userId,
    roles: userRecord.roles,
    createdAt: Date.now(),
  }), { expirationTtl: 60 * 60 * 24 * 30 }); // 30 days

  return jsonResponse({
    token,
    refreshToken,
    userId: userRecord.userId,
    roles: userRecord.roles,
    expiresIn: 3600,
  });
}

async function register(request, env) {
  const { email, password, name } = await request.json();

  if (!email || !password || !name) {
    return jsonResponse({ error: 'Email, password, and name are required' }, 400);
  }

  // Check if user exists
  const existing = await env.AUTH_KV.get(`user:${email}`);
  if (existing) {
    return jsonResponse({ error: 'User already exists' }, 409);
  }

  const userId = crypto.randomUUID();
  const salt = crypto.randomUUID();
  const passwordHash = await hashPassword(password, salt);

  const userRecord = {
    userId,
    email,
    name,
    passwordHash,
    salt,
    roles: ['user'],
    createdAt: Date.now(),
  };

  await env.AUTH_KV.put(`user:${email}`, JSON.stringify(userRecord));
  await env.AUTH_KV.put(`userid:${userId}`, email);

  // Notify user service about new user via service binding if available
  if (env.USER_SERVICE) {
    try {
      await env.USER_SERVICE.fetch('http://internal-service/internal/create', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId, email, name, roles: ['user'] }),
      });
    } catch (e) {
      console.error('Failed to notify user service:', e);
    }
  }

  const token = await generateToken(userId, ['user'], env);

  return jsonResponse({
    token,
    userId,
    message: 'User registered successfully',
    expiresIn: 3600,
  }, 201);
}

async function verifyToken(request, env) {
  const { token } = await request.json();

  if (!token) {
    return jsonResponse({ valid: false, message: 'No token provided' }, 400);
  }

  try {
    const payload = await decodeToken(token, env);
    if (!payload) {
      return jsonResponse({ valid: false, message: 'Invalid token' }, 401);
    }

    if (payload.exp < Date.now() / 1000) {
      return jsonResponse({ valid: false, message: 'Token expired' }, 401);
    }

    // Check if token is blacklisted
    const blacklisted = await env.AUTH_KV.get(`blacklist:${token}`);
    if (blacklisted) {
      return jsonResponse({ valid: false, message: 'Token revoked' }, 401);
    }

    return jsonResponse({
      valid: true,
      userId: payload.sub,
      roles: payload.roles,
      exp: payload.exp,
    });
  } catch (error) {
    return jsonResponse({ valid: false, message: 'Token verification failed' }, 401);
  }
}

async function refreshToken(request, env) {
  const { refreshToken } = await request.json();

  if (!refreshToken) {
    return jsonResponse({ error: 'Refresh token required' }, 400);
  }

  const stored = await env.AUTH_KV.get(`refresh:${refreshToken}`, 'json');
  if (!stored) {
    return jsonResponse({ error: 'Invalid refresh token' }, 401);
  }

  // Invalidate old refresh token
  await env.AUTH_KV.delete(`refresh:${refreshToken}`);

  // Generate new tokens
  const newToken = await generateToken(stored.userId, stored.roles, env);
  const newRefreshToken = crypto.randomUUID();

  await env.AUTH_KV.put(`refresh:${newRefreshToken}`, JSON.stringify({
    userId: stored.userId,
    roles: stored.roles,
    createdAt: Date.now(),
  }), { expirationTtl: 60 * 60 * 24 * 30 });

  return jsonResponse({
    token: newToken,
    refreshToken: newRefreshToken,
    expiresIn: 3600,
  });
}

async function logout(request, env, context) {
  const authHeader = request.headers.get('Authorization');
  if (authHeader) {
    const token = authHeader.replace('Bearer ', '');
    // Blacklist the token for the remaining validity period
    await env.AUTH_KV.put(`blacklist:${token}`, 'true', { expirationTtl: 3600 });
  }
  return jsonResponse({ message: 'Logged out successfully' });
}

async function generateToken(userId, roles, env) {
  const header = btoa(JSON.stringify({ alg: 'HS256', typ: 'JWT' }));
  const payload = btoa(JSON.stringify({
    sub: userId,
    roles,
    iat: Math.floor(Date.now() / 1000),
    exp: Math.floor(Date.now() / 1000) + 3600, // 1 hour
  }));

  const secret = env.JWT_SECRET || 'default-secret-change-me';
  const key = await crypto.subtle.importKey(
    'raw',
    new TextEncoder().encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );

  const signature = await crypto.subtle.sign(
    'HMAC',
    key,
    new TextEncoder().encode(`${header}.${payload}`)
  );

  const sig = btoa(String.fromCharCode(...new Uint8Array(signature)));
  return `${header}.${payload}.${sig}`;
}

async function decodeToken(token, env) {
  const parts = token.split('.');
  if (parts.length !== 3) return null;

  const [header, payload, signature] = parts;

  // Verify signature
  const secret = env.JWT_SECRET || 'default-secret-change-me';
  const key = await crypto.subtle.importKey(
    'raw',
    new TextEncoder().encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['verify']
  );

  const sigBytes = Uint8Array.from(atob(signature), (c) => c.charCodeAt(0));
  const valid = await crypto.subtle.verify(
    'HMAC',
    key,
    sigBytes,
    new TextEncoder().encode(`${header}.${payload}`)
  );

  if (!valid) return null;

  return JSON.parse(atob(payload));
}

async function hashPassword(password, salt) {
  const data = new TextEncoder().encode(password + salt);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(hash)));
}

function parseContext(request) {
  try {
    const contextHeader = request.headers.get('X-Request-Context');
    return contextHeader ? JSON.parse(contextHeader) : {};
  } catch {
    return {};
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });
}


