export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const context = parseContext(request);

    try {
      if (path === '/health') {
        return jsonResponse({ status: 'healthy', service: 'user' });
      }

      // Internal endpoint for auth service to create user profiles
      if (path === '/internal/create' && method === 'POST') {
        return await createUserProfile(request, env);
      }

      // User profile endpoints
      if (path === '/profile' && method === 'GET') {
        return await getUserProfile(context.userId, env);
      }

      if (path === '/profile' && method === 'PUT') {
        return await updateUserProfile(context.userId, request, env);
      }

      if (path === '/profile' && method === 'DELETE') {
        return await deleteUserProfile(context.userId, env);
      }

      // Admin: list users
      if (path === '/list' && method === 'GET') {
        if (!context.roles || !context.roles.includes('admin')) {
          return jsonResponse({ error: 'Forbidden: admin access required' }, 403);
        }
        return await listUsers(url.searchParams, env);
      }

      // Get user by ID (for internal service use or admin)
      const userIdMatch = path.match(/^\/(\w{8}-\w{4}-\w{4}-\w{4}-\w{12})$/);
      if (userIdMatch && method === 'GET') {
        const targetUserId = userIdMatch[1];
        // Allow users to view their own profile or admins to view any
        if (targetUserId !== context.userId && (!context.roles || !context.roles.includes('admin'))) {
          return jsonResponse({ error: 'Forbidden' }, 403);
        }
        return await getUserProfile(targetUserId, env);
      }

      // Preferences
      if (path === '/preferences' && method === 'GET') {
        return await getUserPreferences(context.userId, env);
      }

      if (path === '/preferences' && method === 'PUT') {
        return await updateUserPreferences(context.userId, request, env);
      }

      return jsonResponse({ error: 'User route not found' }, 404);
    } catch (error) {
      console.error('User service error:', error);
      return jsonResponse({ error: 'User service error', message: error.message }, 500);
    }
  },
};

async function createUserProfile(request, env) {
  const { userId, email, name, roles } = await request.json();

  const profile = {
    userId,
    email,
    name,
    roles,
    avatar: null,
    bio: '',
    preferences: {
      theme: 'light',
      notifications: true,
      language: 'en',
    },
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };

  await env.USER_KV.put(`profile:${userId}`, JSON.stringify(profile));

  // Add to user index for listing
  const index = await env.USER_KV.get('user:index', 'json') || [];
  index.push({ userId, email, name, createdAt: profile.createdAt });
  await env.USER_KV.put('user:index', JSON.stringify(index));

  return jsonResponse({ message: 'Profile created', profile }, 201);
}

async function getUserProfile(userId, env) {
  if (!userId) {
    return jsonResponse({ error: 'User ID required' }, 400);
  }

  const profile = await env.USER_KV.get(`profile:${userId}`, 'json');
  if (!profile) {
    return jsonResponse({ error: 'User profile not found' }, 404);
  }

  // Don't expose internal fields
  const { ...publicProfile } = profile;
  return jsonResponse({ profile: publicProfile });
}

async function updateUserProfile(userId, request, env) {
  const updates = await request.json();
  const profile = await env.USER_KV.get(`profile:${userId}`, 'json');

  if (!profile) {
    return jsonResponse({ error: 'User profile not found' }, 404);
  }

  // Only allow updating specific fields
  const allowedFields = ['name', 'bio', 'avatar'];
  const filteredUpdates = {};
  for (const field of allowedFields) {
    if (updates[field] !== undefined) {
      filteredUpdates[field] = updates[field];
    }
  }

  const updatedProfile = {
    ...profile,
    ...filteredUpdates,
    updatedAt: new Date().toISOString(),
  };

  await env.USER_KV.put(`profile:${userId}`, JSON.stringify(updatedProfile));

  return jsonResponse({ message: 'Profile updated', profile: updatedProfile });
}

async function deleteUserProfile(userId, env) {
  await env.USER_KV.delete(`profile:${userId}`);

  // Remove from index
  const index = await env.USER_KV.get('user:index', 'json') || [];
  const updatedIndex = index.filter((u) => u.userId !== userId);
  await env.USER_KV.put('user:index', JSON.stringify(updatedIndex));

  return jsonResponse({ message: 'Profile deleted' });
}

async function listUsers(params, env) {
  const page = parseInt(params.get('page') || '1');
  const limit = Math.min(parseInt(params.get('limit') || '20'), 100);

  const index = await env.USER_KV.get('user:index', 'json') || [];
  const start = (page - 1) * limit;
  const paginatedUsers = index.slice(start, start + limit);

  return jsonResponse({
    users: paginatedUsers,
    pagination: {
      page,
      limit,
      total: index.length,
      totalPages: Math.ceil(index.length / limit),
    },
  });
}

async function getUserPreferences(userId, env) {
  const profile = await env.USER_KV.get(`profile:${userId}`, 'json');
  if (!profile) {
    return jsonResponse({ error: 'User not found' }, 404);
  }
  return jsonResponse({ preferences: profile.preferences });
}

async function updateUserPreferences(userId, request, env) {
  const preferences = await request.json();
  const profile = await env.USER_KV.get(`profile:${userId}`, 'json');

  if (!profile) {
    return jsonResponse({ error: 'User not found' }, 404);
  }

  profile.preferences = { ...profile.preferences, ...preferences };
  profile.updatedAt = new Date().toISOString();

  await env.USER_KV.put(`profile:${userId}`, JSON.stringify(profile));

  return jsonResponse({ message: 'Preferences updated', preferences: profile.preferences });
}

function parseContext(request) {
  try {
    const contextHeader = request.headers.get('X-Request-Context');
    return contextHeader ? JSON.parse(contextHeader) : {};
  } catch {
    return {};
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });
}


