// ==========================================
// Worker 4: Data Service (internal)
// File: data-worker/src/index.js
// ==========================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const context = parseContext(request);

    try {
      if (path === '/health') {
        return jsonResponse({ status: 'healthy', service: 'data' });
      }

      // CRUD for data items scoped to user
      if (path === '/items' && method === 'GET') {
        return await listItems(context.userId, url.searchParams, env);
      }

      if (path === '/items' && method === 'POST') {
        return await createItem(context.userId, request, env, ctx);
      }

      const itemIdMatch = path.match(/^\/items\/(.+)$/);
      if (itemIdMatch) {
        const itemId = itemIdMatch[1];

        if (method === 'GET') {
          return await getItem(context.userId, itemId, env);
        }

        if (method === 'PUT') {
          return await updateItem(context.userId, itemId, request, env);
        }

        if (method === 'DELETE') {
          return await deleteItem(context.userId, itemId, env);
        }
      }

      // Batch operations
      if (path === '/batch' && method === 'POST') {
        return await batchOperation(context.userId, request, env);
      }

      // Search
      if (path === '/search' && method === 'GET') {
        return await searchItems(context.userId, url.searchParams, env);
      }

      // Stats
      if (path === '/stats' && method === 'GET') {
        return await getStats(context.userId, env);
      }

      return jsonResponse({ error: 'Data route not found' }, 404);
    } catch (error) {
      console.error('Data service error:', error);
      return jsonResponse({ error: 'Data service error', message: error.message }, 500);
    }
  },
};

async function createItem(userId, request, env, ctx) {
  const body = await request.json();

  if (!body.title) {
    return jsonResponse({ error: 'Title is required' }, 400);
  }

  const itemId = crypto.randomUUID();
  const item = {
    id: itemId,
    userId,
    title: body.title,
    content: body.content || '',
    tags: body.tags || [],
    metadata: body.metadata || {},
    status: 'active',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };

  // Store in D1 database
  await env.DATA_DB.prepare(
    `INSERT INTO items (id, user_id, title, content, tags, metadata, status, created_at, updated_at)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
  ).bind(
    item.id, item.userId, item.title, item.content,
    JSON.stringify(item.tags), JSON.stringify(item.metadata),
    item.status, item.createdAt, item.updatedAt
  ).run();

  // Also cache in KV for fast reads
  await env.DATA_CACHE.put(`item:${itemId}`, JSON.stringify(item), { expirationTtl: 3600 });

  // Notify user about new item creation via notification service
  if (env.NOTIFICATION_SERVICE) {
    ctx.waitUntil(
      env.NOTIFICATION_SERVICE.fetch('http://internal-service/internal/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId,
          type: 'item_created',
          title: 'New Item Created',
          message: `Your item "${item.title}" has been created successfully.`,
          data: { itemId },
        }),
      }).catch((e) => console.error('Notification failed:', e))
    );
  }

  return jsonResponse({ message: 'Item created', item }, 201);
}

async function getItem(userId, itemId, env) {
  // Try cache first
  const cached = await env.DATA_CACHE.get(`item:${itemId}`, 'json');
  if (cached && cached.userId === userId) {
    return jsonResponse({ item: cached, source: 'cache' });
  }

  // Fallback to D1
  const result = await env.DATA_DB.prepare(
    'SELECT * FROM items WHERE id = ? AND user_id = ?'
  ).bind(itemId, userId).first();

  if (!result) {
    return jsonResponse({ error: 'Item not found' }, 404);
  }

  const item = {
    ...result,
    tags: JSON.parse(result.tags || '[]'),
    metadata: JSON.parse(result.metadata || '{}'),
  };

  // Update cache
  await env.DATA_CACHE.put(`item:${itemId}`, JSON.stringify(item), { expirationTtl: 3600 });

  return jsonResponse({ item, source: 'database' });
}

async function updateItem(userId, itemId, request, env) {
  const updates = await request.json();

  const existing = await env.DATA_DB.prepare(
    'SELECT * FROM items WHERE id = ? AND user_id = ?'
  ).bind(itemId, userId).first();

  if (!existing) {
    return jsonResponse({ error: 'Item not found' }, 404);
  }

  const allowedFields = ['title', 'content', 'tags', 'metadata', 'status'];
  const setClauses = [];
  const values = [];

  for (const field of allowedFields) {
    if (updates[field] !== undefined) {
      setClauses.push(`${field} = ?`);
      values.push(
        ['tags', 'metadata'].includes(field)
          ? JSON.stringify(updates[field])
          : updates[field]
      );
    }
  }

  if (setClauses.length === 0) {
    return jsonResponse({ error: 'No valid fields to update' }, 400);
  }

  setClauses.push('updated_at = ?');
  values.push(new Date().toISOString());
  values.push(itemId, userId);

  await env.DATA_DB.prepare(
    `UPDATE items SET ${setClauses.join(', ')} WHERE id = ? AND user_id = ?`
  ).bind(...values).run();

  // Invalidate cache
  await env.DATA_CACHE.delete(`item:${itemId}`);

  return jsonResponse({ message: 'Item updated', itemId });
}

async function deleteItem(userId, itemId, env) {
  const result = await env.DATA_DB.prepare(
    'DELETE FROM items WHERE id = ? AND user_id = ?'
  ).bind(itemId, userId).run();

  if (result.changes === 0) {
    return jsonResponse({ error: 'Item not found' }, 404);
  }

  await env.DATA_CACHE.delete(`item:${itemId}`);

  return jsonResponse({ message: 'Item deleted', itemId });
}

async function listItems(userId, params, env) {
  const page = parseInt(params.get('page') || '1');
  const limit = Math.min(parseInt(params.get('limit') || '20'), 100);
  const status = params.get('status') || 'active';
  const offset = (page - 1) * limit;

  const countResult = await env.DATA_DB.prepare(
    'SELECT COUNT(*) as total FROM items WHERE user_id = ? AND status = ?'
  ).bind(userId, status).first();

  const results = await env.DATA_DB.prepare(
    'SELECT * FROM items WHERE user_id = ? AND status = ? ORDER BY created_at DESC LIMIT ? OFFSET ?'
  ).bind(userId, status, limit, offset).all();

  const items = results.results.map((item) => ({
    ...item,
    tags: JSON.parse(item.tags || '[]'),
    metadata: JSON.parse(item.metadata || '{}'),
  }));

  return jsonResponse({
    items,
    pagination: {
      page,
      limit,
      total: countResult.total,
      totalPages: Math.ceil(countResult.total / limit),
    },
  });
}

async function searchItems(userId, params, env) {
  const query = params.get('q') || '';
  const tag = params.get('tag');
  const limit = Math.min(parseInt(params.get('limit') || '20'), 100);

  let sql = 'SELECT * FROM items WHERE user_id = ? AND status = ?';
  const bindings = [userId, 'active'];

  if (query) {
    sql += ' AND (title LIKE ? OR content LIKE ?)';
    bindings.push(`%${query}%`, `%${query}%`);
  }

  if (tag) {
    sql += ' AND tags LIKE ?';
    bindings.push(`%"${tag}"%`);
  }

  sql += ' ORDER BY created_at DESC LIMIT ?';
  bindings.push(limit);

  const results = await env.DATA_DB.prepare(sql).bind(...bindings).all();

  const items = results.results.map((item) => ({
    ...item,
    tags: JSON.parse(item.tags || '[]'),
    metadata: JSON.parse(item.metadata || '{}'),
  }));

  return jsonResponse({ items, query, tag });
}

async function batchOperation(userId, request, env) {
  const { operations } = await request.json();

  if (!Array.isArray(operations) || operations.length === 0) {
    return jsonResponse({ error: 'Operations array required' }, 400);
  }

  if (operations.length > 50) {
    return jsonResponse({ error: 'Maximum 50 operations per batch' }, 400);
  }

  const results = [];
  const batch = [];

  for (const op of operations) {
    if (op.action === 'delete' && op.itemId) {
      batch.push(
        env.DATA_DB.prepare('DELETE FROM items WHERE id = ? AND user_id = ?')
          .bind(op.itemId, userId)
      );
      results.push({ action: 'delete', itemId: op.itemId, status: 'queued' });
    } else if (op.action === 'update_status' && op.itemId && op.status) {
      batch.push(
        env.DATA_DB.prepare('UPDATE items SET status = ?, updated_at = ? WHERE id = ? AND user_id = ?')
          .bind(op.status, new Date().toISOString(), op.itemId, userId)
      );
      results.push({ action: 'update_status', itemId: op.itemId, status: 'queued' });
    }
  }

  if (batch.length > 0) {
    await env.DATA_DB.batch(batch);
  }

  return jsonResponse({ message: 'Batch operations completed', results });
}

async function getStats(userId, env) {
  const stats = await env.DATA_DB.prepare(`
    SELECT 
      COUNT(*) as total_items,
      SUM(CASE WHEN status = 'active' THEN 1 ELSE 0 END) as active_items,
      SUM(CASE WHEN status = 'archived' THEN 1 ELSE 0 END) as archived_items,
      MIN(created_at) as first_item_date,
      MAX(created_at) as last_item_date
    FROM items WHERE user_id = ?
  `).bind(userId).first();

  return jsonResponse({ stats });
}

function parseContext(request) {
  try {
    const contextHeader = request.headers.get('X-Request-Context');
    return contextHeader ? JSON.parse(contextHeader) : {};
  } catch {
    return {};
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });
}


// ==========================================
// Data Worker wrangler.toml
// File: data-worker/wrangler.toml
// ==========================================

/*
name = "data-worker"
main = "src/index.js"
compatibility_date = "2024-01-01"

# No public routes

[[d1_databases]]
binding = "DATA_DB"
database_name = "data-service-db"
database_id = "your-d1-database-id"

[[kv_namespaces]]
binding = "DATA_CACHE"
id = "your-data-cache-kv-id"

# Service binding for cross-service communication
[[services]]
binding = "NOTIFICATION_SERVICE"
service = "notification-worker"
*/


// ==========================================
// D1 Database Schema
// File: data-worker/schema.sql
// ==========================================

/*
CREATE TABLE IF NOT EXISTS items (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  title TEXT NOT NULL,
  content TEXT DEFAULT '',
  tags TEXT DEFAULT '[]',
  metadata TEXT DEFAULT '{}',
  status TEXT DEFAULT 'active',
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
);

CREATE INDEX idx_items_user_id ON items(user_id);
CREATE INDEX idx_items_status ON items(status);
CREATE INDEX idx_items_created_at ON items(created_at);
CREATE INDEX idx_items_user_status ON items(user_id, status);
*/


// ==========================================
// Worker 5: Notification Service (internal)
// File: notification-worker/src/index.js
// ==========================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const context = parseContext(request);

    try {
      if (path === '/health') {
        return jsonResponse({ status: 'healthy', service: 'notification' });
      }

      // Internal endpoint for other services to send notifications
      if (path === '/internal/send' && method === 'POST') {
        return await sendNotification(request, env);
      }

      // Internal batch send
      if (path === '/internal/broadcast' && method === 'POST') {
        return await broadcastNotification(request, env);
      }

      // User-facing endpoints (accessed via gateway with auth context)
      if (path === '/list' && method === 'GET') {
        return await listNotifications(context.userId, url.searchParams, env);
      }

      if (path === '/unread-count' && method === 'GET') {
        return await getUnreadCount(context.userId, env);
      }

      const notifIdMatch = path.match(/^\/(.+)\/read$/);
      if (notifIdMatch && method === 'POST') {
        return await markAsRead(context.userId, notifIdMatch[1], env);
      }

      if (path === '/read-all' && method === 'POST') {
        return await markAllAsRead(context.userId, env);
      }

      if (path === '/settings' && method === 'GET') {
        return await getNotificationSettings(context.userId, env);
      }

      if (path === '/settings' && method === 'PUT') {
        return await updateNotificationSettings(context.userId, request, env);
      }

      return jsonResponse({ error: 'Notification route not found' }, 404);
    } catch (error) {
      console.error('Notification service error:', error);
      return jsonResponse({ error: 'Notification service error', message: error.message }, 500);
    }
  },

  // Queue consumer for async notification processing
  async queue(batch, env) {
    for (const message of batch.messages) {
      try {
        const notification = message.body;
        await processNotification(notification, env);
        message.ack();
      } catch (error) {
        console.error('Queue processing error:', error);
        message.retry();
      }
    }
  },
};

async function sendNotification(request, env) {
  const { userId, type, title, message, data, channels } = await request.json();

  if (!userId || !type || !title) {
    return jsonResponse({ error: 'userId, type, and title are required' }, 400);
  }

  const notificationId = crypto.randomUUID();
  const notification = {
    id: notificationId,
    userId,
    type,
    title,
    message: message || '',
    data: data || {},
    channels: channels || ['in-app'],
    read: false,
    createdAt: new Date().toISOString(),
  };

  // Store notification
  await storeNotification(notification, env);

  // If queue is available, enqueue for async processing (e.g., email, push)
  if (env.NOTIFICATION_QUEUE) {
    try {
      await env.NOTIFICATION_QUEUE.send(notification);
    } catch (e) {
      console.error('Failed to enqueue notification:', e);
    }
  }

  return jsonResponse({ message: 'Notification sent', notificationId }, 201);
}

async function broadcastNotification(request, env) {
  const { userIds, type, title, message, data } = await request.json();

  if (!Array.isArray(userIds) || userIds.length === 0) {
    return jsonResponse({ error: 'userIds array required' }, 400);
  }

  const notifications = [];
  for (const userId of userIds) {
    const notificationId = crypto.randomUUID();
    const notification = {
      id: notificationId,
      userId,
      type,
      title,
      message: message || '',
      data: data || {},
      channels: ['in-app'],
      read: false,
      createdAt: new Date().toISOString(),
    };

    await storeNotification(notification, env);
    notifications.push(notificationId);
  }

  return jsonResponse({
    message: `Broadcast sent to ${userIds.length} users`,
    notificationIds: notifications,
  }, 201);
}

async function storeNotification(notification, env) {
  // Store individual notification
  await env.NOTIFICATION_KV.put(
    `notif:${notification.id}`,
    JSON.stringify(notification),
    { expirationTtl: 60 * 60 * 24 * 30 } // 30 days
  );

  // Add to user's notification list
  const listKey = `user-notifs:${notification.userId}`;
  const existingList = await env.NOTIFICATION_KV.get(listKey, 'json') || [];
  existingList.unshift({
    id: notification.id,
    type: notification.type,
    title: notification.title,
    read: false,
    createdAt: notification.createdAt,
  });

  // Keep only last 200 notifications in the index
  const trimmedList = existingList.slice(0, 200);
  await env.NOTIFICATION_KV.put(listKey, JSON.stringify(trimmedList));

  // Update unread count
  const countKey = `unread:${notification.userId}`;
  const currentCount = parseInt(await env.NOTIFICATION_KV.get(countKey) || '0');
  await env.NOTIFICATION_KV.put(countKey, String(currentCount + 1));
}

async function listNotifications(userId, params, env) {
  if (!userId) {
    return jsonResponse({ error: 'User ID required' }, 400);
  }

  const page = parseInt(params.get('page') || '1');
  const limit = Math.min(parseInt(params.get('limit') || '20'), 50);
  const type = params.get('type');
  const unreadOnly = params.get('unread') === 'true';

  const listKey = `user-notifs:${userId}`;
  let notifications = await env.NOTIFICATION_KV.get(listKey, 'json') || [];

  // Filter
  if (type) {
    notifications = notifications.filter((n) => n.type === type);
  }
  if (unreadOnly) {
    notifications = notifications.filter((n) => !n.read);
  }

  const total = notifications.length;
  const start = (page - 1) * limit;
  const paged = notifications.slice(start, start + limit);

  // Fetch full notification details
  const detailed = await Promise.all(
    paged.map(async (n) => {
      const full = await env.NOTIFICATION_KV.get(`notif:${n.id}`, 'json');
      return full || n;
    })
  );

  return jsonResponse({
    notifications: detailed,
    pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
  });
}

async function getUnreadCount(userId, env) {
  const count = parseInt(await env.NOTIFICATION_KV.get(`unread:${userId}`) || '0');
  return jsonResponse({ unreadCount: count });
}

async function markAsRead(userId, notificationId, env) {
  const notif = await env.NOTIFICATION_KV.get(`notif:${notificationId}`, 'json');

  if (!notif || notif.userId !== userId) {
    return jsonResponse({ error: 'Notification not found' }, 404);
  }

  if (!notif.read) {
    notif.read = true;
    notif.readAt = new Date().toISOString();
    await env.NOTIFICATION_KV.put(`notif:${notificationId}`, JSON.stringify(notif));

    // Update the list index
    const listKey = `user-notifs:${userId}`;
    const list = await env.NOTIFICATION_KV.get(listKey, 'json') || [];
    const updated = list.map((n) => (n.id === notificationId ? { ...n, read: true } : n));
    await env.NOTIFICATION_KV.put(listKey, JSON.stringify(updated));

    // Decrement unread count
    const countKey = `unread:${userId}`;
    const currentCount = Math.max(0, parseInt(await env.NOTIFICATION_KV.get(countKey) || '0') - 1);
    await env.NOTIFICATION_KV.put(countKey, String(currentCount));
  }

  return jsonResponse({ message: 'Notification marked as read' });
}

async function markAllAsRead(userId, env) {
  const listKey = `user-notifs:${userId}`;
  const list = await env.NOTIFICATION_KV.get(listKey, 'json') || [];

  const now = new Date().toISOString();
  const updated = list.map((n) => ({ ...n, read: true }));
  await env.NOTIFICATION_KV.put(listKey, JSON.stringify(updated));

  // Update individual notifications
  await Promise.all(
    list.filter((n) => !n.read).map(async (n) => {
      const full = await env.NOTIFICATION_KV.get(`notif:${n.id}`, 'json');
      if (full) {
        full.read = true;
        full.readAt = now;
        await env.NOTIFICATION_KV.put(`notif:${n.id}`, JSON.stringify(full));
      }
    })
  );

  // Reset unread count
  await env.NOTIFICATION_KV.put(`unread:${userId}`, '0');

  return jsonResponse({ message: 'All notifications marked as read' });
}

async function getNotificationSettings(userId, env) {
  const settings = await env.NOTIFICATION_KV.get(`settings:${userId}`, 'json') || {
    inApp: true,
    email: false,
    push: false,
    types: {
      item_created: true,
      item_updated: true,
      item_deleted: true,
      system: true,
    },
    quietHours: {
      enabled: false,
      start: '22:00',
      end: '08:00',
    },
  };

  return jsonResponse({ settings });
}

async function updateNotificationSettings(userId, request, env) {
  const updates = await request.json();
  const current = await env.NOTIFICATION_KV.get(`settings:${userId}`, 'json') || {};
  const merged = deepMerge(current, updates);

  await env.NOTIFICATION_KV.put(`settings:${userId}`, JSON.stringify(merged));

  return jsonResponse({ message: 'Settings updated', settings: merged });
}

async function processNotification(notification, env) {
  // Check user's notification settings
  const settings = await env.NOTIFICATION_KV.get(`settings:${notification.userId}`, 'json');

  if (settings) {
    // Check if notification type is enabled
    if (settings.types && settings.types[notification.type] === false) {
      return;
    }

    // Check quiet hours
    if (settings.quietHours?.enabled) {
      const now = new Date();
      const currentTime = `${String(now.getUTCHours()).padStart(2, '0')}:${String(now.getUTCMinutes()).padStart(2, '0')}`;
      if (isInQuietHours(currentTime, settings.quietHours.start, settings.quietHours.end)) {
        return; // Skip non-in-app notifications during quiet hours
      }
    }

    // Process additional channels
    if (settings.email && notification.channels?.includes('email')) {
      // Integration with email service (e.g., Mailchannels, SendGrid)
      console.log(`Would send email notification to user ${notification.userId}`);
    }

    if (settings.push && notification.channels?.includes('push')) {
      console.log(`Would send push notification to user ${notification.userId}`);
    }
  }
}

function isInQuietHours(current, start, end) {
  if (start <= end) {
    return current >= start && current <= end;
  }
  return current >= start || current <= end;
}

function deepMerge(target, source) {
  const result = { ...target };
  for (const key of Object.keys(source)) {
    if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
      result[key] = deepMerge(result[key] || {}, source[key]);
    } else {
      result[key] = source[key];
    }
  }
  return result;
}

function parseContext(request) {
  try {
    const contextHeader = request.headers.get('X-Request-Context');
    return contextHeader ? JSON.parse(contextHeader) : {};
  } catch {
    return {};
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });
}


