// ==========================================
// Shared Utilities Module
// File: shared/utils.js
// ==========================================

export function parseContext(request) {
  try {
    const contextHeader = request.headers.get('X-Request-Context');
    return contextHeader ? JSON.parse(contextHeader) : {};
  } catch {
    return {};
  }
}

export function jsonResponse(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...extraHeaders,
    },
  });
}

export function createInternalRequest(url, method = 'GET', body = null, context = {}) {
  const options = {
    method,
    headers: {
      'Content-Type': 'application/json',
      'X-Request-Context': JSON.stringify(context),
    },
  };

  if (body && !['GET', 'HEAD'].includes(method)) {
    options.body = JSON.stringify(body);
  }

  return new Request(url, options);
}

export class ServiceRouter {
  constructor() {
    this.routes = [];
  }

  add(method, pattern, handler) {
    const regex = new RegExp('^' + pattern.replace(/:\w+/g, '([^/]+)') + '$');
    this.routes.push({ method, pattern, regex, handler });
    return this;
  }

  get(pattern, handler) { return this.add('GET', pattern, handler); }
  post(pattern, handler) { return this.add('POST', pattern, handler); }
  put(pattern, handler) { return this.add('PUT', pattern, handler); }
  delete(pattern, handler) { return this.add('DELETE', pattern, handler); }

  async handle(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    for (const route of this.routes) {
      if (route.method !== method && route.method !== '*') continue;
      const match = path.match(route.regex);
      if (match) {
        const params = match.slice(1);
        const context = parseContext(request);
        return route.handler({ request, env, ctx, params, context, url });
      }
    }

    return jsonResponse({ error: 'Route not found', path, method }, 404);
  }
}


